from pathlib import Path
import base64

ROOT = Path(__file__).resolve().parents[1]
IMAGE_B64 = r''''''

image_path = ROOT / 'assets' / 'ca-siddharth-bhatia-profile-v3.jpg'
image_path.write_bytes(base64.b64decode(IMAGE_B64))

old_sources = [
    'assets/ca-siddharth-bhatia-profile.png',
    'assets/ca-siddharth-bhatia-profile-v2.png',
    'assets/ca-siddharth-bhatia-profile-v2.jpg',
    'assets/ca-siddharth-bhatia.jpeg',
]
new_source = 'assets/ca-siddharth-bhatia-profile-v3.jpg?v=3'
new_absolute = 'https://siddharthvbhatia-blip.github.io/itrdesk/assets/ca-siddharth-bhatia-profile-v3.jpg?v=3'

for path in ROOT.glob('*.html'):
    text = path.read_text(encoding='utf-8')
    original = text
    for old in old_sources:
        text = text.replace(old, new_source)
    for old in [
        'https://siddharthvbhatia-blip.github.io/itrdesk/assets/ca-siddharth-bhatia-profile.png',
        'https://siddharthvbhatia-blip.github.io/itrdesk/assets/ca-siddharth-bhatia-profile-v2.png',
        'https://siddharthvbhatia-blip.github.io/itrdesk/assets/ca-siddharth-bhatia.jpeg',
    ]:
        text = text.replace(old, new_absolute)
    if text != original:
        path.write_text(text, encoding='utf-8')

css_path = ROOT / 'assets' / 'phase1.css'
if css_path.exists():
    css = css_path.read_text(encoding='utf-8')
    patch = '''\n/* Profile image restoration: ensure the photo itself fills the circular frame */\n.profile-hero-photo,.professional-portrait,.sidebar-portrait{overflow:hidden!important;background:#eef0f4!important}\n.profile-hero-photo img,.professional-portrait img,.sidebar-portrait{display:block!important;opacity:1!important;visibility:visible!important;object-fit:cover!important;object-position:center!important}\n'''
    if 'Profile image restoration' not in css:
        css_path.write_text(css + patch, encoding='utf-8')

print('Restored profile photo asset and updated references.')
